// Package cst defines the data structure for the concrete syntax tree.
//
// These struct definitions are put in a standalone package because the code
// generated by gocc imports them. A standalone package helps avoid circular
// dependencies.
package cst

import (
	"encoding/hex"
	"fmt"
	"strconv"

	"github.com/agodnic/avmc/parser/generated/token"
)

type (
	UintLit struct {
		Value uint64
	}
	BytesLit struct {
		Value []uint8
	}
	BinOp struct {
		R  any
		Op string
		L  any
	}
	UnaryOp struct {
		Op   string
		Expr any
	}
	QualifiedIdent struct {
		PackageName string
		Ident       string
	}
	Call struct {
		QualifiedIdent QualifiedIdent
		Args           []any
	}
	BytesType  struct{}
	Uint64Type struct{}
	VoidType   struct{}
	VarDecl    struct {
		Ident string
		Type  any
		Expr  any
	}
	ConstDecl struct {
		Ident string
		Type  any
		Expr  any
	}
	Assignment struct {
		Ident string
		Expr  any
	}
	Return struct {
		Expr any
	}
	Block struct {
		Stmts []any
	}
	If struct {
		Cond any
		Then Block
		Else any
	}
	FuncDecl struct {
		Ident  string
		Params []Param
		Type   any
		Block  Block
	}
	Param struct {
		Ident string
		Type  any
	}
)

func AppendToParamSlice(slice, item any) ([]Param, error) {
	s := slice.([]Param)
	i := item.(Param)
	return append(s, i), nil
}

func MakeParam(identToken, typeNode any) (Param, error) {
	result := Param{
		Ident: string(identToken.(*token.Token).Lit),
		Type:  typeNode,
	}
	return result, nil
}

func MakeFuncDecl(identToken, argsNode, typeNode, blockNode any) (FuncDecl, error) {

	result := FuncDecl{
		Ident: string(identToken.(*token.Token).Lit),
		Block: blockNode.(Block),
	}
	if argsNode != nil {
		result.Params = argsNode.([]Param)
	}

	if typeNode == nil {
		// NOTE This will have no src line/span information (if we ever add the feature)
		result.Type = VoidType{}
	} else {
		result.Type = typeNode
	}
	return result, nil
}

func MakeIf(exprNode, blockNode, elseNode any) (If, error) {
	result := If{
		Cond: exprNode,
		Then: blockNode.(Block),
		Else: elseNode,
	}
	return result, nil
}

func MakeBlock(stmtsNode any) (Block, error) {
	result := Block{
		Stmts: stmtsNode.([]any),
	}
	return result, nil
}

func MakeReturn(typeNode any) (Return, error) {
	result := Return{
		Expr: typeNode,
	}
	return result, nil
}

func MakeAssignment(identToken, exprNode any) (Assignment, error) {
	result := Assignment{
		Ident: string(identToken.(*token.Token).Lit),
		Expr:  exprNode,
	}
	return result, nil
}

func MakeConstDecl(identToken, typeNode, exprNode any) (ConstDecl, error) {
	result := ConstDecl{
		Ident: string(identToken.(*token.Token).Lit),
		Type:  typeNode,
		Expr:  exprNode,
	}
	return result, nil
}

func MakeVarDecl(identToken, typeNode, exprNode any) (VarDecl, error) {
	result := VarDecl{
		Ident: string(identToken.(*token.Token).Lit),
		Type:  typeNode,
		Expr:  exprNode,
	}
	return result, nil
}

func MakeType(typeToken any) (any, error) {

	s := string(typeToken.(*token.Token).Lit)

	switch s {
	case "uint64":
		return Uint64Type{}, nil
	case "bytes":
		return BytesType{}, nil
	default:
		return nil, fmt.Errorf("unexpected type: %s", s)
	}
}

func MakeCall(qualifiedIdentNode, argsNode any) (Call, error) {
	result := Call{
		QualifiedIdent: qualifiedIdentNode.(QualifiedIdent),
	}
	if argsNode != nil {
		result.Args = argsNode.([]any)
	}
	return result, nil
}

func MakeQualifiedIdent(packageNameToken, identToken any) (QualifiedIdent, error) {
	result := QualifiedIdent{
		Ident: string(identToken.(*token.Token).Lit),
	}
	if packageNameToken != nil {
		result.PackageName = string(packageNameToken.(*token.Token).Lit)

		// Package names are being validated here because
		// we had to express them in the grammar as regular
		// identifiers.
		// All package names are valid identifiers,
		// but not all identifiers are valid package names.
		if !isValidPackageName(result.PackageName) {
			return QualifiedIdent{}, fmt.Errorf("invalid package name")
		}
	}
	return result, nil
}

func MakeUnaryOp(opetatorToken, exprNode any) (UnaryOp, error) {
	result := UnaryOp{
		Op:   string(opetatorToken.(*token.Token).Lit),
		Expr: exprNode,
	}
	return result, nil
}

func MakeBinOp(expr1, operatorToken, expr2 any) (BinOp, error) {
	result := BinOp{
		R:  expr1,
		Op: string(operatorToken.(*token.Token).Lit),
		L:  expr2,
	}
	return result, nil
}

func MakeUintLit(uintLiteralToken any) (UintLit, error) {

	s := string(uintLiteralToken.(*token.Token).Lit)

	value, err := strconv.ParseUint(s, 10, 64)
	if err != nil {
		return UintLit{}, fmt.Errorf("failed to parse integer literal: %w", err)
	}

	result := UintLit{
		Value: value,
	}
	return result, nil
}

func MakeBytesLit(bytesLiteralToken any) (BytesLit, error) {

	s := string(bytesLiteralToken.(*token.Token).Lit)
	s = s[4 : len(s)-1]
	if len(s) == 0 {
		result := BytesLit{}
		return result, nil
	}

	b, err := hex.DecodeString(s)
	if err != nil {
		return BytesLit{}, fmt.Errorf("failed to decode hex literal: %w", err)
	}

	result := BytesLit{
		Value: b,
	}
	return result, nil
}

func isValidPackageName(s string) bool {
	if s == "" {
		return false
	}

	for _, r := range s {
		if (r < 'a' || r > 'z') && (r < '0' || r > '9') {
			return false
		}
	}
	return true
}
